mapper.sql:
/* wms-inbound-iborder-sql-oracle.xml - selectIbHdsql - 입고 지시 헤더 조회 SQL */ SELECT '0' AS CHK , A.CTKEY , C.CTNM , A.OWKEY , A.IBHDTYPECD , A.IBHDKEY , A.IBEXPCTDATE , A.REQORDERNO , A.EXTORDERKEY , A.ACKEY , CASE WHEN IBHDTYPECD = '30' THEN A.ACNM ELSE '' END AS OB_CTNM , CASE WHEN IBHDTYPECD != '30' THEN A.ACNM ELSE '' END AS ACNM , A.IBSTATUSCD , COALESCE(SUM(INITQTY_SKU), 0) AS INITQTY_SKU , COALESCE(SUM(INITQTY), 0) AS INITQTY , COALESCE(ROUND(SUM(INITQTY_INN), 2), 0) AS INITQTY_INN , COALESCE(ROUND(SUM(INITQTY_CTN), 2), 0) AS INITQTY_CTN , COALESCE(ROUND(SUM(INITQTY_PLT), 2), 0) AS INITQTY_PLT , COALESCE(SUM(INITQTY_SLPRC), 0) AS INITQTY_SLPRC , COALESCE(SUM(EXPCTQTY_SKU), 0) AS EXPCTQTY_SKU , COALESCE(SUM(EXPCTQTY), 0) AS EXPCTQTY , COALESCE(ROUND(SUM(EXPCTQTY_INN), 2), 0) AS EXPCTQTY_INN , COALESCE(ROUND(SUM(EXPCTQTY_CTN), 2), 0) AS EXPCTQTY_CTN , COALESCE(ROUND(SUM(EXPCTQTY_PLT), 2), 0) AS EXPCTQTY_PLT , COALESCE(SUM(EXPCTQTY_SLPRC), 0) AS EXPCTQTY_SLPRC , COALESCE(SUM(IBQTY_SKU), 0) AS IBQTY_SKU , COALESCE(SUM(IBQTY), 0) AS IBQTY , COALESCE(ROUND(SUM(IBQTY_INN), 2), 0) AS IBQTY_INN , COALESCE(ROUND(SUM(IBQTY_CTN), 2), 0) AS IBQTY_CTN , COALESCE(ROUND(SUM(IBQTY_PLT), 2), 0) AS IBQTY_PLT , COALESCE(SUM(IBQTY_SLPRC), 0) AS IBQTY_SLPRC , COALESCE(SUM(CNFRMQTY_SKU), 0) AS CNFRMQTY_SKU , COALESCE(SUM(CNFRMQTY), 0) AS CNFRMQTY , COALESCE(ROUND(SUM(CNFRMQTY_INN), 2), 0) AS CNFRMQTY_INN , COALESCE(ROUND(SUM(CNFRMQTY_CTN), 2), 0) AS CNFRMQTY_CTN , COALESCE(ROUND(SUM(CNFRMQTY_PLT), 2), 0) AS CNFRMQTY_PLT , COALESCE(SUM(CNFRMQTY_SLPRC), 0) AS CNFRMQTY_SLPRC , CASE WHEN SUM(IBDTSTATUSCD) > 0 THEN 'N' ELSE 'Y' END AS CLOSEYN , A.INSERTDATE , A.INSERTURKEY , A.UPDATEDATE , A.UPDATEURKEY FROM TWORK_INFO_IB_HD A INNER JOIN ( SELECT A.CTKEY , A.OWKEY , A.IBHDKEY , A.UPRIBDTKEY , CASE WHEN A.INITQTY > 0 THEN 1 ELSE 0 END AS INITQTY_SKU , A.INITQTY , A.INITQTY / NULLIF(COALESCE(C.ICUNITQTY, 0), 0) AS INITQTY_INN , A.INITQTY / NULLIF(COALESCE(D.ICUNITQTY, 0), 0) AS INITQTY_CTN , A.INITQTY / (NULLIF(COALESCE(D.ICUNITQTY, 0), 0) * NULLIF(COALESCE(D.CPPQTY, 0), 0)) AS INITQTY_PLT , A.INITQTY * B.SLPRC AS INITQTY_SLPRC , CASE WHEN A.EXPCTQTY > 0 THEN 1 ELSE 0 END AS EXPCTQTY_SKU , A.EXPCTQTY , A.EXPCTQTY / NULLIF(COALESCE(C.ICUNITQTY, 0), 0) AS EXPCTQTY_INN , A.EXPCTQTY / NULLIF(COALESCE(D.ICUNITQTY, 0), 0) AS EXPCTQTY_CTN , A.EXPCTQTY / (NULLIF(COALESCE(D.ICUNITQTY, 0), 0) * NULLIF(COALESCE(D.CPPQTY, 0), 0)) AS EXPCTQTY_PLT , A.EXPCTQTY * B.SLPRC AS EXPCTQTY_SLPRC , CASE WHEN A.IBQTY > 0 THEN 1 ELSE 0 END AS IBQTY_SKU , A.IBQTY , A.IBQTY / NULLIF(COALESCE(C.ICUNITQTY, 0), 0) AS IBQTY_INN , A.IBQTY / NULLIF(COALESCE(D.ICUNITQTY, 0), 0) AS IBQTY_CTN , A.IBQTY / (NULLIF(COALESCE(D.ICUNITQTY, 0), 0) * NULLIF(COALESCE(D.CPPQTY, 0), 0)) AS IBQTY_PLT , A.IBQTY * B.SLPRC AS IBQTY_SLPRC , CASE WHEN A.CNFRMQTY > 0 THEN 1 ELSE 0 END AS CNFRMQTY_SKU , A.CNFRMQTY , A.CNFRMQTY / NULLIF(COALESCE(C.ICUNITQTY, 0), 0) AS CNFRMQTY_INN , A.CNFRMQTY / NULLIF(COALESCE(D.ICUNITQTY, 0), 0) AS CNFRMQTY_CTN , A.CNFRMQTY / (NULLIF(COALESCE(D.ICUNITQTY, 0), 0) * NULLIF(COALESCE(D.CPPQTY, 0), 0)) AS CNFRMQTY_PLT , A.CNFRMQTY * B.SLPRC AS CNFRMQTY_SLPRC , CASE WHEN A.IBDTSTATUSCD != '91' THEN 1 ELSE 0 END AS IBDTSTATUSCD FROM TWORK_INFO_IB_DT A INNER JOIN TWORK_MST_IC B ON A.CTKEY = B.CTKEY AND A.OWKEY = B.OWKEY AND A.ICKEY = B.ICKEY LEFT OUTER JOIN TWORK_MST_ICUTXTYPE C ON A.CTKEY = C.CTKEY AND A.OWKEY = C.OWKEY AND B.ICUNITKEY = C.ICUNITKEY AND C.ICUNITTYPECD = 'INN' LEFT OUTER JOIN TWORK_MST_ICUTXTYPE D ON A.CTKEY = D.CTKEY AND A.OWKEY = D.OWKEY AND B.ICUNITKEY = D.ICUNITKEY AND D.ICUNITTYPECD = 'CTN' ) B ON A.CTKEY = B.CTKEY AND A.OWKEY = B.OWKEY AND A.IBHDKEY = B.IBHDKEY INNER JOIN TWORK_MST_CT C ON A.CTKEY = C.CTKEY WHERE A.IBSTATUSCD != '99' AND B.UPRIBDTKEY IS NULL AND A.IBHDTYPECD != '50' /* 반품입고 */
AND A.IBEXPCTDATE BETWEEN #{ibexpctdateFrom} || '000000' AND #{ibexpctdateTo} || '235959'
AND A.IBHDTYPECD = #{ibhdtypecd}
AND A.IBSTATUSCD = #{ibstatuscd}
AND A.IBHDKEY = #{ibhdkey}
AND A.EXTORDERKEY = #{extorderkey}
AND A.ACKEY = #{ackey}
GROUP BY A.CTKEY, C.CTNM, A.OWKEY, A.IBHDTYPECD, A.IBHDKEY, A.IBEXPCTDATE, A.REQORDERNO, A.EXTORDERKEY, A.ACKEY, A.ACNM, A.IBSTATUSCD, A.INSERTDATE, A.INSERTURKEY, A.UPDATEDATE, A.UPDATEURKEY

/* wms-inbound-iborder-sql-oracle.xml - selectIbDtsql - 입고 지시 상세 조회 SQL */ WITH RECURSIVE ctg_tree AS ( SELECT CTKEY, OWKEY, CTGKEY, CTGNM, CTGLV, UPRCTGKEY, CTGKEY AS root_ctgkey, 1 AS lvl FROM TWORK_MST_CTG WHERE CTGLV = '1' UNION ALL SELECT c.CTKEY, c.OWKEY, c.CTGKEY, c.CTGNM, c.CTGLV, c.UPRCTGKEY, p.root_ctgkey, p.lvl + 1 FROM TWORK_MST_CTG c INNER JOIN ctg_tree p ON c.UPRCTGKEY = p.CTGKEY AND c.CTKEY = p.CTKEY AND c.OWKEY = p.OWKEY WHERE p.lvl < 3 ), CTG AS ( SELECT CTKEY , OWKEY , root_ctgkey AS CTG1KEY , MAX(CASE WHEN CTGLV = '1' THEN CTGNM END) OVER (PARTITION BY root_ctgkey) AS CTG1NM , MAX(CASE WHEN CTGLV = '2' THEN CTGKEY END) OVER (PARTITION BY root_ctgkey) AS CTG2KEY , MAX(CASE WHEN CTGLV = '2' THEN CTGNM END) OVER (PARTITION BY root_ctgkey) AS CTG2NM , CTGKEY AS CTG3KEY , CTGNM AS CTG3NM FROM ctg_tree ) SELECT * FROM ( SELECT '0' AS CHK , A.CTKEY , A.OWKEY , A.IBHDKEY , A.IBDTKEY , B.IBHDTYPECD , B.IBEXPCTDATE , CASE WHEN B.IBHDTYPECD = '30' THEN B.ACNM ELSE '' END AS OB_CTNM , CASE WHEN B.IBHDTYPECD != '30' THEN B.ACNM ELSE '' END AS ACNM , A.EXTORDERKEY , B.REQORDERNO , C.ACKEY AS IC_ACKEY , D.ACNM AS IC_ACNM , CASE WHEN E.ASRTDTICKEY IS NOT NULL AND A.UPRIBDTKEY IS NOT NULL THEN E.ASRTMASICKEY ELSE A.ICKEY END AS ASRTMASICKEY , CASE WHEN E.ASRTDTICKEY IS NOT NULL AND A.UPRIBDTKEY IS NOT NULL THEN G.ICNM ELSE C.ICNM END AS ASRTMASICNM , CASE WHEN E.ASRTDTICKEY IS NOT NULL AND A.UPRIBDTKEY IS NOT NULL THEN A.ICKEY END AS ASRTDTICKEY , CASE WHEN E.ASRTDTICKEY IS NOT NULL AND A.UPRIBDTKEY IS NOT NULL THEN C.ICNM END AS ASRTDTICNM , A.ASRTWKTGTYN AS ASRTYN , CTG.CTG1NM AS LV1_CTGNM , CTG.CTG2NM AS LV2_CTGNM , CTG.CTG3NM AS LV3_CTGNM , A.UOM , A.IBDTSTATUSCD , COALESCE(A.INITQTY, 0) AS INITQTY , CASE WHEN I.ICUNITQTY IS NULL THEN 0 WHEN A.INITQTY > 0 THEN ROUND(A.INITQTY / COALESCE(I.ICUNITQTY, 1), 2) ELSE COALESCE(A.INITQTY, 0) END AS INITQTY_INN , CASE WHEN J.ICUNITQTY IS NULL THEN 0 WHEN A.INITQTY > 0 THEN ROUND(A.INITQTY / COALESCE(J.ICUNITQTY, 1), 2) ELSE COALESCE(A.INITQTY, 0) END AS INITQTY_CTN , CASE WHEN J.ICUNITQTY IS NULL THEN 0 WHEN A.INITQTY > 0 THEN ROUND(A.INITQTY / (COALESCE(J.ICUNITQTY, 1) * CASE COALESCE(J.CPPQTY, 0) WHEN 0 THEN 1 ELSE J.CPPQTY END), 2) ELSE COALESCE(A.INITQTY, 0) END AS INITQTY_PLT , COALESCE(A.INITQTY * C.SLPRC, 0) AS INITQTY_SLPRC , COALESCE(A.EXPCTQTY, 0) AS EXPCTQTY , CASE WHEN I.ICUNITQTY IS NULL THEN 0 WHEN A.EXPCTQTY > 0 THEN ROUND(A.EXPCTQTY / COALESCE(I.ICUNITQTY, 1), 2) ELSE COALESCE(A.EXPCTQTY, 0) END AS EXPCTQTY_INN , CASE WHEN J.ICUNITQTY IS NULL THEN 0 WHEN A.EXPCTQTY > 0 THEN ROUND(A.EXPCTQTY / COALESCE(J.ICUNITQTY, 1), 2) ELSE COALESCE(A.EXPCTQTY, 0) END AS EXPCTQTY_CTN , CASE WHEN J.ICUNITQTY IS NULL THEN 0 WHEN A.EXPCTQTY > 0 THEN ROUND(A.EXPCTQTY / (COALESCE(J.ICUNITQTY, 1) * CASE COALESCE(J.CPPQTY, 0) WHEN 0 THEN 1 ELSE J.CPPQTY END), 2) ELSE COALESCE(A.EXPCTQTY, 0) END AS EXPCTQTY_PLT , COALESCE(A.EXPCTQTY * C.SLPRC, 0) AS EXPCTQTY_SLPRC , COALESCE(A.IBQTY, 0) AS IBQTY , CASE WHEN I.ICUNITQTY IS NULL THEN 0 WHEN A.IBQTY > 0 THEN ROUND(A.IBQTY / COALESCE(I.ICUNITQTY, 1), 2) ELSE COALESCE(A.IBQTY, 0) END AS IBQTY_INN , CASE WHEN J.ICUNITQTY IS NULL THEN 0 WHEN A.IBQTY > 0 THEN ROUND(A.IBQTY / COALESCE(J.ICUNITQTY, 1), 2) ELSE COALESCE(A.IBQTY, 0) END AS IBQTY_CTN , CASE WHEN J.ICUNITQTY IS NULL THEN 0 WHEN A.IBQTY > 0 THEN ROUND(A.IBQTY / (COALESCE(J.ICUNITQTY, 1) * CASE COALESCE(J.CPPQTY, 0) WHEN 0 THEN 1 ELSE J.CPPQTY END), 2) ELSE COALESCE(A.IBQTY, 0) END AS IBQTY_PLT , COALESCE(A.IBQTY * C.SLPRC, 0) AS IBQTY_SLPRC , COALESCE(A.CNFRMQTY, 0) AS CNFRMQTY , CASE WHEN I.ICUNITQTY IS NULL THEN 0 WHEN A.CNFRMQTY > 0 THEN ROUND(A.CNFRMQTY / COALESCE(I.ICUNITQTY, 1), 2) ELSE COALESCE(A.CNFRMQTY, 0) END AS CNFRMQTY_INN , CASE WHEN J.ICUNITQTY IS NULL THEN 0 WHEN A.CNFRMQTY > 0 THEN ROUND(A.CNFRMQTY / COALESCE(J.ICUNITQTY, 1), 2) ELSE COALESCE(A.CNFRMQTY, 0) END AS CNFRMQTY_CTN , CASE WHEN J.ICUNITQTY IS NULL THEN 0 WHEN A.CNFRMQTY > 0 THEN ROUND(A.CNFRMQTY / (COALESCE(J.ICUNITQTY, 1) * CASE COALESCE(J.CPPQTY, 0) WHEN 0 THEN 1 ELSE J.CPPQTY END), 2) ELSE COALESCE(A.CNFRMQTY, 0) END AS CNFRMQTY_PLT , COALESCE(A.CNFRMQTY * C.SLPRC, 0) AS CNFRMQTY_SLPRC , CASE WHEN A.IBDTSTATUSCD = '91' THEN 'Y' ELSE 'N' END AS CLOSEYN , A.UOM AS IN_UOM , L.ICUNITQTY , 0 AS INQTY_UNIT , 0 AS INQTY , '' AS PRDCTDATE , '' AS EXPDATE , '' AS CNTRNO , 0 AS INWEIGHT , A.IBNISRSNCD , A.IBNISDTRSNCONT , A.ICKEY , C.ICNM , C.EXPCKYN , C.EXPCKTYPECD , C.EXPCNVRSNDAYS , M.CNTRLABELDIVCD , A.INSERTDATE , A.INSERTURKEY , A.UPDATEDATE , A.UPDATEURKEY FROM TWORK_INFO_IB_DT A INNER JOIN TWORK_INFO_IB_HD B ON A.CTKEY = B.CTKEY AND A.OWKEY = B.OWKEY AND A.IBHDKEY = B.IBHDKEY INNER JOIN TWORK_MST_IC C ON A.CTKEY = C.CTKEY AND A.OWKEY = C.OWKEY AND A.ICKEY = C.ICKEY LEFT OUTER JOIN TWORK_MST_AC D ON A.CTKEY = D.CTKEY AND C.ACKEY = D.ACKEY LEFT OUTER JOIN TWORK_MST_ASRT E ON A.CTKEY = E.CTKEY AND A.OWKEY = E.OWKEY AND A.ICKEY = E.ASRTDTICKEY LEFT OUTER JOIN TWORK_MST_IC G ON A.CTKEY = G.CTKEY AND A.OWKEY = G.OWKEY AND E.ASRTMASICKEY = G.ICKEY INNER JOIN CTG ON C.CTKEY = CTG.CTKEY AND C.OWKEY = CTG.OWKEY AND C.CTGKEY = CTG.CTG3KEY LEFT OUTER JOIN TWORK_MST_ICUTXTYPE I ON A.CTKEY = I.CTKEY AND A.OWKEY = I.OWKEY AND C.ICUNITKEY = I.ICUNITKEY AND I.ICUNITTYPECD = 'INN' LEFT OUTER JOIN TWORK_MST_ICUTXTYPE J ON A.CTKEY = J.CTKEY AND A.OWKEY = J.OWKEY AND C.ICUNITKEY = J.ICUNITKEY AND J.ICUNITTYPECD = 'CTN' LEFT OUTER JOIN TWORK_MST_ICUTXTYPE L ON A.CTKEY = L.CTKEY AND A.OWKEY = L.OWKEY AND C.ICUNITKEY = L.ICUNITKEY AND A.UOM = L.ICUNITTYPECD LEFT OUTER JOIN ( SELECT CTKEY, OWKEY, IBHDKEY, IBDTKEY, MAX(CNTRLABELDIVCD) AS CNTRLABELDIVCD FROM TWORK_INFO_B2B_OB_LABEL GROUP BY CTKEY, OWKEY, IBHDKEY, IBDTKEY ) M ON A.CTKEY = M.CTKEY AND A.OWKEY = M.OWKEY AND A.IBHDKEY = M.IBHDKEY AND A.IBDTKEY = M.IBDTKEY WHERE A.CTKEY = #{ctkey} AND A.OWKEY = #{owkey} AND A.IBHDKEY = #{ibhdkey} AND A.IBDTSTATUSCD <> '99' ) A WHERE 1=1
#{item}
#{item}
AND A.ASRTYN = #{asrtyn}
AND A.CLOSEYN = #{closeyn}

/* wms-inbound-iborder-sql-oracle.xml - selectIbDtCf2sql - 입고 지시 확정(부분변경) 상세 조회 SQL */ SELECT '0' AS CHK , A.CTKEY , A.OWKEY , A.IBHDKEY , A.IBDTKEY , B.IBCFSEQNO , A.ICKEY , C.ICNM , A.ICTMPRDIVCD , A.UOM , CASE WHEN A.EXPCTQTY > 0 THEN ROUND(A.EXPCTQTY / COALESCE(D.ICUNITQTY, 1),2) ELSE A.EXPCTQTY END AS EXPCTQTY_UNIT , CASE WHEN B.IBQTY > 0 THEN ROUND(B.IBQTY / COALESCE(D.ICUNITQTY, 1),2) ELSE B.IBQTY END AS IBQTY_UNIT , 0 AS REGQTY_UNIT , A.EXPCTQTY , B.IBQTY , 0 AS REGQTY , D.ICUNITQTY , D.WEIGHT , B.PRDCTDATE , B.EXPDATE , B.IVATKEY , 0 AS REGWEIGHT , A.IBDTSTATUSCD FROM TWORK_INFO_IB_DT A INNER JOIN TWORK_INFO_IBCF_DT B ON A.CTKEY = B.CTKEY AND A.OWKEY = B.OWKEY AND A.IBHDKEY = B.IBHDKEY AND A.IBDTKEY = B.IBDTKEY INNER JOIN TWORK_MST_IC C ON A.CTKEY = C.CTKEY AND A.OWKEY = C.OWKEY AND A.ICKEY = C.ICKEY LEFT OUTER JOIN TWORK_MST_ICUTXTYPE D ON A.CTKEY = D.CTKEY AND A.OWKEY = D.OWKEY AND A.ICUNITKEY = D.ICUNITKEY AND A.UOM = D.ICUNITTYPECD WHERE 1=1 AND A.IBHDKEY = #{ibhdkey}
AND (A.ICKEY LIKE '%' || #{icnm} || '%' OR C.ICNM LIKE '%' || #{icnm} || '%')
AND (A.IBDTSTATUSCD LIKE #{ibdtstatuscd})

