/* wms-inbound-iborder-sql-oracle.xml - selectIbHdCntCheck - 입고 헤더 체크*/
SELECT COUNT(*)
  FROM TWORK_INFO_IB_HD
 WHERE CTKEY = #{ctkey}
   AND IBHDKEY = #{ibhdkey}

/* wms-inbound-iborder-sql-oracle.xml - selectIbDtCntCheck - 입고 상세 체크*/
SELECT COUNT(*)
  FROM TWORK_INFO_IB_DT
 WHERE CTKEY = #{ctkey}
   AND IBHDKEY = #{ibhdkey}
   AND IBDTKEY = #{ibdtkey}

/* wms-inbound-iborder-sql-oracle.xml - selectIbMstIcCntCheck - 상품 체크 */
