  FROM TWORK_MST_OW
 WHERE OWKEY = #{owkey}

/* wms-inbound-iborder-sql-oracle.xml - selectB2bObLabelCntrLabeldivcd - B2B출고 용기라벨구분코드 조회 */
SELECT MAX(CNTRLABELDIVCD) AS CNTRLABELDIVCD
  FROM TWORK_INFO_B2B_OB_LABEL
 WHERE CTKEY = #{ctkey}
   AND OWKEY = #{owkey}
   AND IBHDKEY = #{ibhdkey}
   AND IBDTKEY = #{ibdtkey}

mapper.update:
/* wms-inbound-iborder-sql-oracle.xml - updateIbDtIbdtstatuscd - 입고 상세 수량 작업상태 수정 */
UPDATE TWORK_INFO_IB_DT
   SET IBDTSTATUSCD = (
                        SELECT CASE WHEN B.EXPCTQTY = A.IBQTY THEN '40' /* 검수 완료 */
                                    WHEN B.EXPCTQTY > A.IBQTY AND A.IBQTY > 0 THEN '30' /* 부분 검수 */
                                    ELSE '00' END AS WKSTATUS
                          FROM (
                                SELECT SUM(IBQTY) AS IBQTY
                                     , SUM(CNFRMQTY) AS CNFRMQTY
                                     , CTKEY
                                     , OWKEY
                                     , IBHDKEY
                                     , IBDTKEY
                                  FROM TWORK_INFO_IBCF_DT
                                 WHERE CTKEY = #{ctkey}
                                   AND OWKEY = #{owkey}
                                   AND IBHDKEY = #{ibhdkey}
                                   AND IBDTKEY = #{ibdtkey}
                                 GROUP BY CTKEY, OWKEY, IBHDKEY, IBDTKEY
                                 UNION ALL
                                SELECT 0 AS IBQTY
                                     , 0 AS CNFRMQTY
                                     , #{ctkey} AS CTKEY
                                     , #{owkey} AS OWKEY
                                     , #{ibhdkey} AS IBHDKEY
                                     , #{ibdtkey} AS IBDTKEY
                                 WHERE NOT EXISTS (
                                                SELECT 1
                                                  FROM TWORK_INFO_IBCF_DT
                                                 WHERE CTKEY = #{ctkey}
                                                   AND OWKEY = #{owkey}
                                                   AND IBHDKEY = #{ibhdkey}
                                                   AND IBDTKEY = #{ibdtkey}
                                                   )
                                ) A
                            INNER JOIN TWORK_INFO_IB_DT B
                               ON A.CTKEY = B.CTKEY
                              AND A.OWKEY = B.OWKEY
                              AND A.IBHDKEY = B.IBHDKEY
                              AND A.IBDTKEY = B.IBDTKEY
                        )
     , IBQTY = IBQTY + #{ibqty}
     , PLCMSTATUSCD = #{plcmstatuscd}
     , IBNISRSNCD = #{ibnisrsncd}
     , IBNISDTRSNCONT = #{ibnisdtrsncont}
     , ASRTWKCOMPLYN = CASE WHEN IBQTY + #{ibqty} = ASRTWKQTY THEN 'Y'
                            ELSE 'N' END
     , WKCHNLCD = #{wkchnlcd}
     , UPDATEDATE = #{sysdate}
     , UPDATEURKEY = #{surkey}
 WHERE CTKEY = #{ctkey}
   AND OWKEY = #{owkey}
   AND IBHDKEY = #{ibhdkey}
   AND IBDTKEY = #{ibdtkey}

/* wms-inbound-iborder-sql-oracle.xml - updateIbHdIbstatuscd - 입고 헤더 작업상태 수정 */
 UPDATE TWORK_INFO_IB_HD
	SET IBSTATUSCD = (
						SELECT CASE WHEN TOTAL_QTY = IB_QTY						  THEN '40'	/* 검수완료 */
									WHEN IB_QTY > 0 OR PART_IB_QTY	> 0			  THEN '30'	/* 부분검수 */
									ELSE '00' END AS WKSTATUS
						  FROM (
								SELECT SUM(PUTAWAY_QTY) 		 AS PUTAWAY_QTY
									 , SUM(PART_PUTAWAY_QTY)     AS PART_PUTAWAY_QTY
									 , SUM(IB_QTY)  		 	 AS IB_QTY
									 , SUM(PART_IB_QTY) 		 AS PART_IB_QTY
									 , SUM(TOTAL_QTY) 		 	 AS TOTAL_QTY
								  FROM (
										SELECT CASE WHEN IBDTSTATUSCD = '90' THEN 1
													ELSE 0 END AS PUTAWAY_QTY
											 , CASE WHEN IBDTSTATUSCD = '85' THEN 1
													ELSE 0 END AS PART_PUTAWAY_QTY
											 , CASE WHEN IBDTSTATUSCD = '40' THEN 1
													ELSE 0 END AS IB_QTY
											 , CASE WHEN IBDTSTATUSCD = '30' THEN 1
													ELSE 0 END AS PART_IB_QTY
											 , 1 AS TOTAL_QTY
										  FROM TWORK_INFO_IB_DT
										 WHERE CTKEY   = #{ctkey}
										   AND OWKEY   = #{owkey}
										   AND IBHDKEY = #{ibhdkey}
									 )
								) sub_1
					 )
	  , UPDATEDATE 		= #{sysdate}
	  , UPDATEURKEY 	= #{surkey}
  WHERE CTKEY   		= #{ctkey}
	AND OWKEY   		= #{owkey}
	AND IBHDKEY 		= #{ibhdkey}

mapper.select:
/* wms-inbound-iborder-sql-oracle.xml - selectB2bObLabel - B2B 출고 라벨 정보 조회 */
SELECT *
  FROM TWORK_INFO_B2B_OB_LABEL
 WHERE CTKEY = #{ctkey}
   AND OWKEY = #{owkey}
   AND IBHDKEY = #{ibhdkey}
   AND IBDTKEY = #{ibdtkey}

    AND CNTRLABELNO = #{cntrno}


    AND BOXLABELNO = #{boxlabelno}

ORDER BY BOXLABELNO

mapper.update:
/* wms-inbound-iborder-sql-oracle.xml - updateB2bObLabelPrcsyn - B2B 출고 라벨 처리 여부 수정 */
UPDATE TWORK_INFO_B2B_OB_LABEL
   SET PRCSYN = #{prcsyn}
     , IBQTY = #{ibqty}
     , IBCFSEQNO = #{ibcfseqno}
     , UPDATEDATE = #{sysdate}
     , UPDATEURKEY = #{surkey}
 WHERE CTKEY = #{ctkey}
   AND OWKEY = #{owkey}
   AND IBHDKEY = #{ibhdkey}
   AND IBDTKEY = #{ibdtkey}
   AND BOXLABELNO = #{boxlabelno}

/* wms-inbound-iborder-sql-oracle.xml - updateIbnisrsn - 결품 사유 저장 */
UPDATE TWORK_INFO_IB_DT
   SET IBNISRSNCD = #{ibnisrsncd}
     , IBNISDTRSNCONT = #{ibnisdtrsncont}
     , UPDATEDATE = #{sysdate}
     , UPDATEURKEY = #{surkey}
 WHERE CTKEY = #{ctkey}
   AND OWKEY = #{owkey}
   AND IBHDKEY = #{ibhdkey}
   AND IBDTKEY = #{ibdtkey}

mapper.select:
/* wms-inbound-iborder-sql-oracle.xml - selectIbOrderCntrTransfer - 용기환적 조회 */ SELECT '0' AS CHK , A.CTKEY , A.OWKEY , A.IBHDKEY , A.IBDTKEY , A.IBCFSEQNO , B.IBCNFRMDATE , A.ICKEY , C.ICNM , A.EXPDATE , A.CNTRNO AS BFCHGCNTRNO , A.IBQTY , A.IVATKEY , A.QTY , '' AS CNTRNO , '' AS UOM , 0 AS TRANSQTY_UNIT , 0 AS TRANSQTY , 0 AS ICUNITQTY FROM TWORK_INFO_IBCF_CNTR A INNER JOIN TWORK_INFO_IBCF_DT B ON A.CTKEY = B.CTKEY AND A.OWKEY = B.OWKEY AND A.IBHDKEY = B.IBHDKEY AND A.IBDTKEY = B.IBDTKEY AND A.IBCFSEQNO = B.IBCFSEQNO INNER JOIN TWORK_MST_IC C ON A.CTKEY = C.CTKEY AND A.OWKEY = C.OWKEY AND A.ICKEY = C.ICKEY WHERE A.CTKEY = #{ctkey} AND A.OWKEY = #{owkey}
AND B.IBCNFRMDATE BETWEEN #{ibcnfrmdateFrom} || '000000' AND #{ibcnfrmdateTo} || '235959'
AND A.ICKEY = #{ickey}
AND (A.ICKEY LIKE '%' || #{icnm} || '%' OR C.ICNM LIKE '%' || #{icnm} || '%')
AND A.CNTRNO = #{cntrno}
AND A.IBHDKEY = #{ibhdkey}

/* wms-inbound-iborder-sql-oracle.xml - selectIbcfCntrMap - 입고확정 용기 조회 */
SELECT *
  FROM TWORK_INFO_IBCF_CNTR
 WHERE CTKEY   = #{ctkey}
   AND OWKEY   = #{owkey}
   AND IBHDKEY = #{ibhdkey}
   AND IBDTKEY = #{ibdtkey}
   AND ICKEY   = #{ickey}
   AND IVATKEY = #{ivatkey}
   AND CNTRNO  = #{bfchgcntrno}

/* wms-inbound-iborder-sql-oracle.xml - selectIbcfCntrBfchgcntrnoCnt - 입고확정 용기환적된 것 조회 */
SELECT COUNT(*)
  FROM TWORK_INFO_IBCF_CNTR
 WHERE CTKEY   = #{ctkey}
   AND OWKEY   = #{owkey}
   AND IBHDKEY = #{ibhdkey}
   AND IBDTKEY = #{ibdtkey}
   AND ICKEY   = #{ickey}
   AND IVATKEY = #{ivatkey}
   AND BFCHGCNTRNO  = #{cntrno}
   AND CNTRNO != BFCHGCNTRNO

    AND IBCFSEQNO = #{ibcfseqno}

/* wms-inbound-iborder-sql-oracle.xml - selectIbDtCurrentQtyForUpdate - 입고수량 조회 */
SELECT IBQTY
  FROM TWORK_INFO_IB_DT
 WHERE CTKEY = #{ctkey}
   AND OWKEY = #{owkey}
   AND IBHDKEY = #{ibhdkey}
   AND IBDTKEY = #{ibdtkey}

/* wms-inbound-iborder-sql-oracle.xml - selectIbDtQtyCheck - 출고라벨 요청수량 초과 건수 조회 */
SELECT COUNT(*)
  FROM (
        SELECT CTKEY
             , OWKEY
             , IBHDKEY
             , IBDTKEY
             , SUM(QTY) AS QTY
             , SUM(IBQTY) AS IBQTY
          FROM TWORK_INFO_B2B_OB_LABEL
         WHERE CTKEY = #{ctkey}
           AND OWKEY = #{owkey}
           AND IBHDKEY = #{ibhdkey}
           AND IBDTKEY = #{ibdtkey}
         GROUP BY CTKEY, OWKEY, IBHDKEY, IBDTKEY
) T
WHERE T.IBQTY + #{inqty} > T.QTY

/* wms-inbound-iborder-sql-oracle.xml - selectIbOrderObLabelCount - 출고라벨 건수 조회 */ SELECT COUNT(*) FROM ( SELECT B.ACNM , A.IBHDKEY , B.IBEXPCTDATE , A.DLVYDAY , A.ICKEY , C.ICNM , A.EXPDATE , A.QTY AS EA_QTY , CASE WHEN D.ICUNITQTY IS NULL THEN 0 WHEN A.QTY > 0 THEN ROUND(A.QTY / COALESCE(D.ICUNITQTY, 1), 2) ELSE COALESCE(A.QTY, 0) END AS INN_QTY , CASE WHEN E.ICUNITQTY IS NULL THEN 0 WHEN A.QTY > 0 THEN ROUND(A.QTY / COALESCE(E.ICUNITQTY, 1), 2) ELSE COALESCE(A.QTY, 0) END AS CTN_QTY , A.BOXLABELNO , A.CNTRLABELDIVCD , A.CNTRLABELNO FROM TWORK_INFO_B2B_OB_LABEL A INNER JOIN TWORK_INFO_IB_HD B ON A.CTKEY = B.CTKEY AND A.OWKEY = B.OWKEY AND A.IBHDKEY = B.IBHDKEY INNER JOIN TWORK_MST_IC C ON A.CTKEY = C.CTKEY AND A.OWKEY = C.OWKEY AND A.ICKEY = C.ICKEY LEFT OUTER JOIN TWORK_MST_ICUTXTYPE D ON A.CTKEY = D.CTKEY AND A.OWKEY = D.OWKEY AND C.ICUNITKEY = D.ICUNITKEY AND D.ICUNITTYPECD = 'INN' LEFT OUTER JOIN TWORK_MST_ICUTXTYPE E ON A.CTKEY = E.CTKEY AND A.OWKEY = E.OWKEY AND C.ICUNITKEY = E.ICUNITKEY AND E.ICUNITTYPECD = 'CTN' WHERE A.CTKEY = #{ctkey} AND A.OWKEY = #{owkey}
AND B.IBEXPCTDATE BETWEEN #{ibexpctdateFrom} || '000000' AND #{ibexpctdateTo} || '235959'
AND A.ICKEY = #{ickey}
AND (A.ICKEY LIKE '%' || #{icnm} || '%' OR C.ICNM LIKE '%' || #{icnm} || '%')
AND A.CNTRLABELNO = #{cntrno}
AND A.IBHDKEY = #{ibhdkey}
AND B.ACKEY = #{ackey}
ORDER BY A.IBHDKEY, A.IBDTKEY ) A

/* wms-inbound-iborder-sql-oracle.xml - selectIbOrderObLabel - 출고라벨 조회 */ #{GRIDPAGING_ROWNUMTYPE_TOP} SELECT * FROM ( SELECT B.ACNM , A.IBHDKEY , B.IBEXPCTDATE , A.DLVYDAY , A.ICKEY , C.ICNM , A.EXPDATE , A.QTY AS EA_QTY , CASE WHEN D.ICUNITQTY IS NULL THEN 0 WHEN A.QTY > 0 THEN ROUND(A.QTY / COALESCE(D.ICUNITQTY, 1), 2) ELSE COALESCE(A.QTY, 0) END AS INN_QTY , CASE WHEN E.ICUNITQTY IS NULL THEN 0 WHEN A.QTY > 0 THEN ROUND(A.QTY / COALESCE(E.ICUNITQTY, 1), 2) ELSE COALESCE(A.QTY, 0) END AS CTN_QTY , A.BOXLABELNO , A.CNTRLABELDIVCD , A.CNTRLABELNO FROM TWORK_INFO_B2B_OB_LABEL A INNER JOIN TWORK_INFO_IB_HD B ON A.CTKEY = B.CTKEY AND A.OWKEY = B.OWKEY AND A.IBHDKEY = B.IBHDKEY INNER JOIN TWORK_MST_IC C ON A.CTKEY = C.CTKEY AND A.OWKEY = C.OWKEY AND A.ICKEY = C.ICKEY LEFT OUTER JOIN TWORK_MST_ICUTXTYPE D ON A.CTKEY = D.CTKEY AND A.OWKEY = D.OWKEY AND C.ICUNITKEY = D.ICUNITKEY AND D.ICUNITTYPECD = 'INN' LEFT OUTER JOIN TWORK_MST_ICUTXTYPE E ON A.CTKEY = E.CTKEY AND A.OWKEY = E.OWKEY AND C.ICUNITKEY = E.ICUNITKEY AND E.ICUNITTYPECD = 'CTN' WHERE A.CTKEY = #{ctkey} AND A.OWKEY = #{owkey}
AND B.IBEXPCTDATE BETWEEN #{ibexpctdateFrom} || '000000' AND #{ibexpctdateTo} || '235959'
AND A.ICKEY = #{ickey}
AND (A.ICKEY LIKE '%' || #{icnm} || '%' OR C.ICNM LIKE '%' || #{icnm} || '%')
AND A.CNTRLABELNO = #{cntrno}
AND A.IBHDKEY = #{ibhdkey}
AND B.ACKEY = #{ackey}
ORDER BY A.IBHDKEY, A.IBDTKEY ) A #{GRIDPAGING_ROWNUMTYPE_BOTTOM}
